const callResult = $json.call_result || 'unknown';
const interestLevel = $json.interest_level || 'none';
const painPoints = $json.pain_points || '';
const nextStep = $json.next_step || 'callback';
const notes = $json.notes || '';

// Generar mensaje de cierre apropiado según el resultado
let closingMessage = '';
let internalNote = '';

switch (nextStep) {
  case 'meeting_scheduled':
    closingMessage = "Thank you so much for your time today! You'll receive the calendar invite shortly. Nataly is looking forward to speaking with you. Have a wonderful day!";
    internalNote = `HIGH INTEREST - Meeting scheduled. Pain points: ${painPoints}. ${notes}`;
    break;

  case 'send_email':
    closingMessage = "I'll send that information over to your email right away. Feel free to reach out if you have any questions after reviewing. Thank you for your time, have a great day!";
    internalNote = `MEDIUM INTEREST - Requested email follow-up. Pain points: ${painPoints}. ${notes}`;
    break;

  case 'callback':
    closingMessage = "I appreciate your time today. I'll follow up with you soon. Have a great day!";
    internalNote = `LOW INTEREST - Schedule callback. ${notes}`;
    break;

  case 'not_interested':
    closingMessage = "I completely understand. Thank you for your time today. If anything changes in the future, don't hesitate to reach out. Have a wonderful day!";
    internalNote = `NOT INTERESTED - Do not call again. ${notes}`;
    break;

  default:
    closingMessage = "Thank you for your time today. Have a great day!";
    internalNote = notes;
}

return [{
  json: {
    response: closingMessage,
    call_result: callResult,
    interest_level: interestLevel,
    pain_points: painPoints,
    next_step: nextStep,
    notes: internalNote,
    timestamp: new Date().toISOString()
  }
}];
